import pickle
import json
from typing import Any, Dict, List, Union

def save_preferences(preferences: Dict[str, Any], filename: str) -> None:
    """Save user preferences to a file using pickle for optimal performance."""
    with open(filename, 'wb') as f:
        pickle.dump(preferences, f)

def load_preferences(filename: str) -> Dict[str, Any]:
    """Load user preferences from a file."""
    try:
        with open(filename, 'rb') as f:
            return pickle.load(f)
    except FileNotFoundError:
        return {}

class CustomObject:
    def __init__(self, name: str, value: int):
        self.name = name
        self.value = value
    
    def __eq__(self, other):
        return isinstance(other, CustomObject) and self.name == other.name and self.value == other.value